const impressions = Number($node['Fetch X Ads Metrics'].json.impressions) || 0;
const urlClicks = Number($node['Fetch X Ads Metrics'].json.url_clicks) || 0;
const ctr = impressions > 0 ? urlClicks / impressions : 0;
return [{ json: { ctr, impressions, url_clicks: urlClicks } }];

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const week = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}週`;

const ctr = $node['Calculate CTR'].json.ctr;
const signups = Number($node['Fetch GA4 Signups'].json.signups) || 0;
const prevRow = $node['Load Previous Week Metrics'].json || {};

const prevCtrRaw = prevRow.prev_ctr;
const prevSignupsRaw = prevRow.prev_signups;

const prev_ctr = (prevCtrRaw === undefined || prevCtrRaw === '' || prevCtrRaw === null) ? null : Number(prevCtrRaw);
const prev_signups = (prevSignupsRaw === undefined || prevSignupsRaw === '' || prevSignupsRaw === null) ? null : Number(prevSignupsRaw);

const payload = { week, ctr, signups, prev_ctr, prev_signups };

return [{ json: { ...payload, payloadJsonString: JSON.stringify(payload) } }];

const LP_URL_PLACEHOLDER = "{{LP_URL}}";
const POST_AXES = {
  A: {
    hook: "AIの必要性はわかっているのに、自社でどこから始めるべきか判断がつかず、止まっていませんか？",
    bullets: [
      "自社の業務のどこにAIを使うべきかが整理できる",
      "「まず着手すべき1つの領域」とその理由が明確になる",
      "個別相談で自社に合った次の一手まで相談できる",
    ],
  },
  B: {
    hook: "人手不足と属人化で、現場がもう限界に近づいていませんか？",
    bullets: [
      "属人化している業務の棚卸しができる",
      "AIで巻き取れる業務の見極め方がわかる",
      "少ない人数でも回る仕組みづくりの第一歩がわかる",
    ],
  },
};
const BENEFIT_LINE = "60分で、自社にとっての「初手の判断軸」を整理できる無料セミナーです。";

function buildPostText(axisKey, options) {
  options = options || {};
  const axis = POST_AXES[axisKey];
  if (!axis) throw new Error('Unknown axis: "' + axisKey + '". Expected "A" or "B".');
  const lpUrl = options.lpUrl || LP_URL_PLACEHOLDER;
  const hook = options.tweak ? axis.hook + options.tweak : axis.hook;
  const bullets = axis.bullets.map(function (b) { return "・" + b; }).join("\n");
  return hook + "\n\n" + bullets + "\n\n" + BENEFIT_LINE + "\n\n詳細・お申込みはこちら▼ " + lpUrl;
}

function classifyWeek(input) {
  const ctr = input.ctr, signups = input.signups, prev_ctr = input.prev_ctr, prev_signups = input.prev_signups;
  const isBaseline = prev_ctr === null || prev_ctr === undefined || prev_signups === null || prev_signups === undefined;
  if (isBaseline) {
    return { status: "baseline", reason: "前週データがなく比較対象がないため、今週の実績をベースラインとして扱い、A/Bテスト用の投稿案を作成します。" };
  }
  const signupsOk = signups >= prev_signups;
  const ctrOk = ctr >= prev_ctr;
  if (signupsOk && ctrOk) {
    return { status: "keep", reason: "申込数(" + signups + "件、前週" + prev_signups + "件)・CTR(" + ctr + "、前週" + prev_ctr + ")ともに前週以上のため、現状維持とし、軽微な文言改善のみ行います。" };
  }
  if (signupsOk && !ctrOk) {
    return { status: "replace_post", reason: "申込数(" + signups + "件)は前週(" + prev_signups + "件)以上を維持していますが、CTRが前週(" + prev_ctr + ")より悪化(" + ctr + ")しているため、投稿文を差し替えます。" };
  }
  if (!signupsOk && ctrOk) {
    return { status: "improve_lp", reason: "CTRは前週(" + prev_ctr + ")以上を維持(" + ctr + ")していますが、申込数が前週(" + prev_signups + "件)より減少(" + signups + "件)しているため、投稿の軸は維持しつつLP改善を優先します。" };
  }
  return { status: "replace_post_and_improve_lp", reason: "CTR(" + ctr + " < 前週" + prev_ctr + ")・申込数(" + signups + "件 < 前週" + prev_signups + "件)がともに悪化しているため、投稿差し替えとLP改善の両方を行います。" };
}

function generateLpSuggestions() {
  return [
    "見出し改善案: 「AI導入、何から始める？を60分で言語化する無料セミナー」のように、所要時間と得られる結果を見出しに明示する。",
    "導入文改善案: 冒頭1文目で「何から手をつければいいか分からない」という悩みに具体的に共感し、2文目で本セミナーが提供する解決の方向性を提示する。",
    "ベネフィット順改善案: 最も刺さりやすい「最初の一手が明確になる」ベネフィットを先頭に配置し、次に個別相談導線、最後に信頼要素（実績・登壇者情報）の順に並べる。",
  ];
}

function generateWeeklyReport(input) {
  const c = classifyWeek(input);
  const status = c.status, reason = c.reason;
  let next_post_A = null, next_post_B = null, lp_suggestions = [];
  if (status === "baseline" || status === "replace_post" || status === "replace_post_and_improve_lp") {
    next_post_A = buildPostText("A");
    next_post_B = buildPostText("B");
  } else if (status === "keep") {
    next_post_A = buildPostText("A", { tweak: "（今なら個別相談も無料）" });
    next_post_B = buildPostText("B", { tweak: "（今なら個別相談も無料）" });
  } else if (status === "improve_lp") {
    next_post_A = null;
    next_post_B = null;
  }
  if (status === "improve_lp" || status === "replace_post_and_improve_lp") {
    lp_suggestions = generateLpSuggestions();
  }
  return { week: input.week, status: status, reason: reason, next_post_A: next_post_A, next_post_B: next_post_B, lp_suggestions: lp_suggestions };
}

const report = generateWeeklyReport($json);
return [{ json: { stdout: JSON.stringify(report) } }];

const stdout = $json.stdout || $json.data || '';
if (!stdout) {
  throw new Error('PDCA script returned empty stdout');
}
let parsed;
try {
  parsed = JSON.parse(stdout.trim());
} catch (e) {
  throw new Error('Failed to parse PDCA stdout as JSON: ' + e.message);
}
return [{ json: parsed }];

